class Solution:
    def maximumSum(self, nums):
        def ds(x):
            s = 0
            while x:
                s += x % 10
                x //= 10
            return s
        best = -1
        n = len(nums)
        for i in range(n):
            for j in range(i + 1, n):
                if ds(nums[i]) == ds(nums[j]):
                    best = max(best, nums[i] + nums[j])
        return best

