class Solution:
    def maximumSum(self, nums):
        def ds(x):
            s = 0
            while x:
                s += x % 10
                x //= 10
            return s
        best = -1
        top = {}
        for v in nums:
            d = ds(v)
            if d in top:
                best = max(best, top[d] + v)
                if v > top[d]:
                    top[d] = v
            else:
                top[d] = v
        return best

