var maximumSum = function(nums) {
    const ds = (x) => { let s = 0; while (x) { s += x % 10; x = Math.floor(x / 10); } return s; };
    let best = -1;
    const top = new Map();
    for (const v of nums) {
        const d = ds(v);
        if (top.has(d)) {
            best = Math.max(best, top.get(d) + v);
            if (v > top.get(d)) top.set(d, v);
        } else {
            top.set(d, v);
        }
    }
    return best;
};
